#!/usr/bin/env python3
# Read-only audit: flag installed extensions whose manifest grants broad standing authority
# (all-sites host permissions, cookies, webRequest) that survives the one-time install consent.
import json, sys
SAMPLE = {"name": "helper", "permissions": ["cookies", "webRequest", "<all_urls>", "tabs"], "host_permissions": ["*://*/*"]}
m = SAMPLE  # in a real run: load each extension's manifest.json from the profile dir
broad = {"<all_urls>", "*://*/*", "cookies", "webRequest", "webRequestBlocking", "tabs", "scripting"}
hits = [p for p in (m.get("permissions", []) + m.get("host_permissions", [])) if p in broad]
if hits:
    print("VULNERABLE: extension '%s' holds standing authority %s — inherits the app session on every page" % (m.get("name"), hits))
else:
    print("PASS: no broad standing permissions")
